import { useState, useEffect, useRef, useTransition, useCallback } from "react";
import { useLocation, useNavigate } from "react-router-dom";
import { clearRestaurantFilters } from "@/lib/clearRestaurantFilters";
import { useTranslation } from "react-i18next";
import { Home, Store, Calendar, Users } from "lucide-react";
import { useEnvironment } from "@/hooks/useEnvironment";
import { useSiteSettings } from "@/hooks/useSiteSettings";
import { useNavigationSettings } from "@/hooks/useNavigationSettings";

const MobileBottomNav = () => {
  const { t } = useTranslation();
  const location = useLocation();
  const navigate = useNavigate();
  const { isWebView } = useEnvironment();
  const { settings } = useSiteSettings();
  const { buttons, isLoading: isLoadingNav } = useNavigationSettings();
  const [visible, setVisible] = useState(true);
  const [isPending, startTransition] = useTransition();
  const frameRef = useRef<number | null>(null);
  const isHomePage = location.pathname === "/";

  useEffect(() => {
    if (!isHomePage) {
      setVisible(true);
      return;
    }

    const updateVisibility = () => {
      try {
        const currentY = window.scrollY || window.pageYOffset || 0;
        const viewportHeight = window.innerHeight || document.documentElement?.clientHeight || 800;
        const shouldShow = currentY >= viewportHeight * 0.30;
        setVisible((prev) => (prev === shouldShow ? prev : shouldShow));
      } catch {
        setVisible(true);
      }
    };

    const handleScroll = () => {
      if (frameRef.current !== null) return;
      frameRef.current = window.requestAnimationFrame(() => {
        frameRef.current = null;
        updateVisibility();
      });
    };

    try {
      updateVisibility();
      window.addEventListener("scroll", handleScroll, { passive: true });
    } catch {
      setVisible(true);
    }

    return () => {
      try {
        if (frameRef.current !== null) {
          window.cancelAnimationFrame(frameRef.current);
          frameRef.current = null;
        }
        window.removeEventListener("scroll", handleScroll);
      } catch {}
    };
  }, [isHomePage]);

  // Only show on specific pages
  const allowedPaths = ['/', '/restaurants', '/activities', '/community', '/community/posts', '/community/recipes'];
  const isRestaurantSubpath = location.pathname.startsWith('/restaurants/');
  const isAllowedPath = allowedPaths.includes(location.pathname) || isRestaurantSubpath;
  if (!isAllowedPath) {
    return null;
  }

  // Only show in webview on mobile
  if (!isWebView) {
    return null;
  }

  // Don't render navigation until buttons are loaded to prevent flash
  if (isLoadingNav) {
    return null;
  }

  const isCommunityEnabled = settings?.community_enabled !== false;

  // Check if a specific link is enabled and visible in navigation buttons
  const isLinkEnabled = (link: string) => {
    const button = buttons?.find((btn) => btn.link === link);
    // If no button found, assume enabled
    if (!button) return true;
    // Check if the button is enabled AND visible
    // enabled=false means completely disabled (feature off)
    // visible=false means hidden from navigation
    return button.enabled !== false && button.visible !== false;
  };

  const baseMenuItems = [
    { title: t("nav.map"), url: "/", icon: Home },
    { title: t("nav.restaurants"), url: "/restaurants", icon: Store },
    { title: t("nav.activities"), url: "/activities", icon: Calendar },
  ];

  // Add community if enabled
  if (isCommunityEnabled) {
    baseMenuItems.push({ title: t("nav.community"), url: "/community", icon: Users });
  }

  // Filter out disabled links
  const menuItems = baseMenuItems.filter((item) => isLinkEnabled(item.url));

  const isActive = (path: string) => {
    if (path === "/") return location.pathname === path;
    return location.pathname.startsWith(path);
  };

  return (
    <nav className={`fixed bottom-4 left-4 right-4 z-50 rounded-[28px] safe-bottom lg:hidden overflow-hidden transition-transform duration-200 ease-out will-change-transform bg-background/95 border border-border/60 shadow-sm ${visible ? "translate-y-0" : "translate-y-[calc(100%+2rem)]"}`}>
      {/* 顶部柔和高光渐变 - 更微妙的自然反光 */}
      <div className="absolute inset-0 rounded-[28px] bg-gradient-to-b from-background/40 via-transparent to-transparent pointer-events-none" />
      
      <div className="relative flex justify-around items-center h-14 px-4">
        {menuItems.map((item) => (
          <button
            key={item.url}
            type="button"
            onClick={() => {
              if (item.url.startsWith('/restaurants')) clearRestaurantFilters();
              startTransition(() => {
                navigate(item.url);
              });
            }}
            className={`relative flex flex-col items-center justify-center flex-1 h-10 py-1 px-2 mx-0.5 transition-all duration-200 rounded-2xl ${
              isActive(item.url)
                ? "text-primary dark:text-white bg-primary/15 dark:bg-white/15"
                : "text-gray-700 dark:text-white/80 active:bg-black/5 dark:active:bg-white/5"
            }`}
          >
            <item.icon 
              className={`h-5 w-5 mb-1 transition-all duration-200 ${
                isActive(item.url) 
                  ? "scale-110 drop-shadow-[0_0_6px_rgba(34,197,94,0.6)] dark:drop-shadow-[0_0_6px_rgba(255,255,255,0.6)]" 
                  : ""
              }`} 
            />
            <span className={`text-xs text-center line-clamp-1 ${isActive(item.url) ? "font-semibold" : "font-normal"}`}>
              {item.title}
            </span>
          </button>
        ))}
      </div>
    </nav>
  );
};

export default MobileBottomNav;
